def test__array_with_holes(client) -> None:
    """Array indices with gaps should be rejected in form data."""
    response = client.post(
        "/items",
        json="items[0]=first&items[2]=third&items[5]=sixth",
        headers={
            "Content-Type": "application/x-www-form-urlencoded",
        },
    )
    assert response.status_code == 400  # noqa: S101
    data = response.json()
    assert data == {
        "error": "Failed to parse URL-encoded form data: missing index, expected: 1 got 2"
    }  # noqa: S101


